#include "test_framework.hpp"
#include "flow/flow.hpp"
#include <initializer_list>
#include <unordered_set>

using namespace cryo;
using namespace cryo_test;

namespace {

void assert_set_eq(const std::unordered_set<NodeId>& actual,
                   std::initializer_list<NodeId> expected_values) {
    std::unordered_set<NodeId> expected(expected_values);
    assert_eq(actual.size(), expected.size());
    for (auto node : expected) {
        assert_true(actual.count(node) == 1, "missing expected node");
    }
}

void assert_min_cut_consistent(const Graph& g,
                               const MinCutResult& cut,
                               NodeId source,
                               NodeId sink) {
    assert_true(cut.source_side.count(source) == 1, "source must be on source side");
    assert_true(cut.sink_side.count(sink) == 1, "sink must be on sink side");

    for (auto node : g.node_ids()) {
        const bool in_source = cut.source_side.count(node) == 1;
        const bool in_sink = cut.sink_side.count(node) == 1;
        assert_true(in_source != in_sink, "node must be in exactly one cut side");
    }

    std::unordered_set<EdgeId> expected_cut_edge_ids;
    double expected_cut_capacity = 0.0;
    g.for_each_edge([&](const Edge& e) {
        if (cut.source_side.count(e.src) == 1 && cut.sink_side.count(e.dst) == 1) {
            expected_cut_edge_ids.insert(e.id);
            expected_cut_capacity += e.weight;
        }
    });

    std::unordered_set<EdgeId> actual_cut_edge_ids;
    double actual_cut_capacity = 0.0;
    for (const auto& e : cut.cut_edges) {
        assert_true(cut.source_side.count(e.src) == 1, "cut edge source must be on source side");
        assert_true(cut.sink_side.count(e.dst) == 1, "cut edge destination must be on sink side");
        actual_cut_edge_ids.insert(e.id);
        actual_cut_capacity += e.weight;
    }

    assert_eq(actual_cut_edge_ids.size(), expected_cut_edge_ids.size());
    for (auto edge_id : expected_cut_edge_ids) {
        assert_true(actual_cut_edge_ids.count(edge_id) == 1, "missing expected cut edge");
    }
    assert_near(actual_cut_capacity, cut.cut_value);
    assert_near(expected_cut_capacity, cut.cut_value);
}

} // namespace

CRYO_TEST(Flow, MinCutSaturatedEdgesDoNotLeakSourceSide) {
    Graph g(GraphType::Directed);
    for (NodeId node = 0; node < 3; node++) g.add_node_with_id(node);
    EdgeId source_cut_edge = g.add_edge(0, 1, 1.0);
    g.add_edge(1, 2, 1.0);

    auto cut = min_cut(g, 0, 2);

    assert_near(cut.cut_value, 1.0);
    assert_set_eq(cut.source_side, {0});
    assert_set_eq(cut.sink_side, {1, 2});
    assert_eq(cut.cut_edges.size(), (size_t)1);
    assert_eq(cut.cut_edges[0].id, source_cut_edge);
    assert_min_cut_consistent(g, cut, 0, 2);
}

CRYO_TEST(Flow, MinCutUsesReverseResidualReachability) {
    Graph g(GraphType::Directed);
    for (NodeId node = 0; node < 5; node++) g.add_node_with_id(node);
    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(1, 3, 1.0);
    g.add_edge(2, 3, 1.0);
    EdgeId sink_cut_edge = g.add_edge(3, 4, 1.0);

    auto cut = min_cut(g, 0, 4);

    assert_near(cut.cut_value, 1.0);
    assert_set_eq(cut.source_side, {0, 1, 2, 3});
    assert_set_eq(cut.sink_side, {4});
    assert_eq(cut.cut_edges.size(), (size_t)1);
    assert_eq(cut.cut_edges[0].id, sink_cut_edge);
    assert_min_cut_consistent(g, cut, 0, 4);
}

CRYO_TEST(Flow, MinCutDisconnectedNodesStayOnSinkSide) {
    Graph g(GraphType::Directed);
    for (NodeId node = 0; node < 4; node++) g.add_node_with_id(node);
    g.add_edge(0, 1, 5.0);

    auto cut = min_cut(g, 0, 2);

    assert_near(cut.cut_value, 0.0);
    assert_set_eq(cut.source_side, {0, 1});
    assert_set_eq(cut.sink_side, {2, 3});
    assert_true(cut.cut_edges.empty());
    assert_min_cut_consistent(g, cut, 0, 2);
}

